function Notifications() {

  return (

    <div className="container mt-5">

      <h2>
        Notifications
      </h2>

      <div className="alert alert-success">

        Appointment Confirmed

      </div>

      <div className="alert alert-info">

        Doctor Available

      </div>

    </div>

  );

}

export default Notifications;
